55	const basePremiums: Record<string, number> = {
56	  sword: 100,
57	  amulet: 60,
58	  staff: 80,
59	  potion: 40,
60	  rune: 25,
61	  moonstone: 25,
62	};
63	
64	const PROCESSING_FEE = 5;
65	
66	const BLOCK_SIZE = 3;
67	
68	const BLOCK_OF_THREE_BASE = 60;
69	
70	const componentTypes = new Set(["rune", "moonstone"]);
71	
72	const tallyBy = <T>(
73	  items: T[],
74	  keyOf: (item: T) => string
75	): Record<string, number> =>
76	  items.reduce<Record<string, number>>((counts, item) => {
77	    const key = keyOf(item);
78	    counts[key] = (counts[key] ?? 0) + 1;
79	    return counts;
80	  }, {});
81	
82	const countByType = (items: QuoteItem[]): Record<string, number> =>
83	  tallyBy(items, (item) => item.type);
84	
85	const basePremiumFor = (type: string): number => {
86	  if (!(type in basePremiums)) {
87	    throw new Error(`Unknown item type: ${type}`);
88	  }
89	  return basePremiums[type];
90	};
91	
92	const basePremiumForGroup = (type: string, count: number): number => {
93	  if (componentTypes.has(type) && count === BLOCK_SIZE) {
94	    return BLOCK_OF_THREE_BASE;
95	  }
96	  return basePremiumFor(type) * count;
97	};
98	
99	const CURSE_SURCHARGE_RATE = 0.5;
100	
101	const FIRST_INSURANCE_RATE = 0.1;
102	
103	const HIGH_ENCHANTMENT_THRESHOLD = 5;
104	
105	const HIGH_ENCHANTMENT_RATE = 0.3;
106	
107	const itemBasePremium = (item: QuoteItem): number =>
108	  basePremiumFor(item.type);
109	
110	const isCursed = (item: QuoteItem): boolean => item.cursed === true;
111	
112	const curseSurcharge = (item: QuoteItem): number =>
113	  isCursed(item) ? itemBasePremium(item) * CURSE_SURCHARGE_RATE : 0;
114	
115	const enchantmentLevel = (item: QuoteItem): number => item.enchantment ?? 0;
116	
117	const highEnchantmentSurcharge = (item: QuoteItem): number =>
118	  enchantmentLevel(item) >= HIGH_ENCHANTMENT_THRESHOLD
119	    ? itemBasePremium(item) * HIGH_ENCHANTMENT_RATE
120	    : 0;
121	
122	const firstInsuranceSurcharge = (item: QuoteItem): number =>
123	  itemBasePremium(item) * FIRST_INSURANCE_RATE;
124	
125	const itemSurcharges = (item: QuoteItem): number =>
126	  curseSurcharge(item) +
127	  highEnchantmentSurcharge(item) +
128	  firstInsuranceSurcharge(item);
129	
130	const sumOfBasePremiums = (items: QuoteItem[]): number => {
131	  const counts = countByType(items);
132	  return Object.entries(counts).reduce(
133	    (sum, [type, count]) => sum + basePremiumForGroup(type, count),
134	    0
135	  );
136	};
137	
138	const sumOfItemSurcharges = (items: QuoteItem[]): number =>
139	  items.reduce((sum, item) => sum + itemSurcharges(item), 0);
140	
141	const LOYALTY_YEARS_THRESHOLD = 2;
142	
143	const LOYALTY_DISCOUNT_RATE = 0.2;
144	
145	const loyaltyDiscount = (customer: Customer, basePremium: number): number =>
146	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD
147	    ? basePremium * LOYALTY_DISCOUNT_RATE
148	    : 0;
149	
150	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
151	
152	const followUpDiscount = (basePremium: number, isFollowUp: boolean): number =>
153	  isFollowUp ? basePremium * FOLLOW_UP_DISCOUNT_RATE : 0;
154	
155	const quotePremium = (
156	  items: QuoteItem[],
157	  customer: Customer,
158	  isFollowUp: boolean
159	): number => {
160	  const basePremium = sumOfBasePremiums(items);
161	  const surcharges = sumOfItemSurcharges(items);
162	  const discount =
163	    loyaltyDiscount(customer, basePremium) +
164	    followUpDiscount(basePremium, isFollowUp);
165	  return Math.ceil(basePremium + surcharges - discount + PROCESSING_FEE);
166	};
167	
168	const isFollowUpQuote = (steps: Step[], index: number): boolean =>
169	  steps.slice(0, index).some((step) => step.op === "quote");
170	
171	const insuranceValues: Record<string, number> = {
172	  sword: 1000,
173	  amulet: 600,
174	  staff: 800,
175	  potion: 400,
176	  rune: 250,
177	  moonstone: 250,
178	};
179	
180	const DEDUCTIBLE = 100;
181	
182	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
183	
184	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
185	
186	const isHighEnchantmentClaim = (policyItem: QuoteItem | undefined): boolean =>
187	  (policyItem?.enchantment ?? 0) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD;
188	
189	const damagePayout = (damage: Damage, policyItems: QuoteItem[]): number => {
190	  const policyItem = policyItems.find((item) => item.type === damage.itemType);
191	  if (policyItem === undefined) {
192	    throw new Error(`Damage item not in policy: ${damage.itemType}`);
193	  }
194	  const reimbursable = isHighEnchantmentClaim(policyItem)
195	    ? damage.amount * HIGH_ENCHANTMENT_REIMBURSEMENT_RATE
196	    : damage.amount;
197	  return reimbursable - DEDUCTIBLE;
198	};
199	
200	const CAP_MULTIPLIER = 2;
201	
202	const insuranceCap = (policyItems: QuoteItem[]): number =>
203	  CAP_MULTIPLIER *
204	  policyItems.reduce((sum, item) => sum + insuranceValues[item.type], 0);
205	
206	const totalDamagePayout = (
207	  damages: Damage[],
208	  policyItems: QuoteItem[]
209	): number =>
210	  damages.reduce((total, damage) => total + damagePayout(damage, policyItems), 0);
211	
212	const policyItemsFor = (scenario: Scenario, policy: number): QuoteItem[] =>
213	  (scenario.steps[policy] as QuoteStep).items;
214	
215	const countDamagesByType = (damages: Damage[]): Record<string, number> =>
216	  tallyBy(damages, (damage) => damage.itemType);
217	
218	const validateDamageCounts = (
219	  damages: Damage[],
220	  policyItems: QuoteItem[]
221	): void => {
222	  const insuredCounts = countByType(policyItems);
223	  const damageCounts = countDamagesByType(damages);
224	  for (const [itemType, count] of Object.entries(damageCounts)) {
225	    if (count > (insuredCounts[itemType] ?? 0)) {
226	      throw new Error(`Too many damages for item type: ${itemType}`);
227	    }
228	  }
229	};
230	
231	const claimResult = (
232	  step: ClaimStep,
233	  policyItems: QuoteItem[],
234	  cap: number
235	): ClaimResult => {
236	  validateDamageCounts(step.incident.damages, policyItems);
237	  const desiredPayout = Math.floor(
238	    totalDamagePayout(step.incident.damages, policyItems)
239	  );
240	  const payout = Math.min(desiredPayout, cap);
241	  return { payout, remainingCap: cap - payout };
242	};
243	
244	export function runScenario(scenario: Scenario): ScenarioResult {
245	  const remainingCaps = new Map<number, number>();
246	  const results = scenario.steps.map((step, index): StepResult => {
247	    if (step.op === "claim") {
248	      const policyItems = policyItemsFor(scenario, step.policy);
249	      const cap = remainingCaps.get(step.policy) ?? insuranceCap(policyItems);
250	      const result = claimResult(step, policyItems, cap);
251	      remainingCaps.set(step.policy, result.remainingCap);
252	      return result;
253	    }
254	    const isFollowUp = isFollowUpQuote(scenario.steps, index);
255	    return {
256	      premium: quotePremium(step.items, scenario.customer, isFollowUp),
257	    };
258	  });
259	  return { results };
260	}
261

